def get_median(nums):
    if not nums: return 0
    s = sorted(nums)
    n = len(s)
    mid = n // 2
    if n % 2 == 0:
        return (s[mid - 1] + s[mid]) / 2
    return s[mid]

if __name__ == "__main__":
    print(f"Median: {get_median([4, 1, 2, 3])}")

